Here are the public test cases for feature9_output_dirs:
{
  "description": "Resolve the effective output, sources and resources directories from a partially specified configuration. If all three are given they are kept as-is. If the root output is omitted it falls back to the sources dir, else the resources dir, else a directory derived from the input file's base name; the sources and resources directories, when omitted, default to fixed sub-folders under the resolved root. Output is three lines: 'out=', 'src=', 'res='.",
  "cases": [
    {
      "input": {
        "feature": "output_dirs",
        "input_name": "some.apk",
        "out_dir": "r",
        "src_dir": "s",
        "res_dir": "r"
      },
      "expected_output": "out=r\nsrc=s\nres=r\n"
    },
    {
      "input": {
        "feature": "output_dirs",
        "input_name": "some.apk",
        "out_dir": "out",
        "src_dir": null,
        "res_dir": null
      },
      "expected_output": "out=out\nsrc=out/sources\nres=out/resources\n"
    },
    {
      "input": {
        "feature": "output_dirs",
        "input_name": "some.apk",
        "out_dir": null,
        "src_dir": "src",
        "res_dir": null
      },
      "expected_output": "out=src\nsrc=src\nres=src/resources\n"
    },
    {
      "input": {
        "feature": "output_dirs",
        "input_name": "some.apk",
        "out_dir": null,
        "src_dir": null,
        "res_dir": "res"
      },
      "expected_output": "out=res\nsrc=res/sources\nres=res\n"
